#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n;    cin >> n;        vll a(n),b,c;    for(int i=0; i<n; i++) cin >> a[i];    long long maxi=*max_element(a.begin(),a.end());    for(int i=0; i<n; i++){        if(a[i]!=maxi) b.push_back(a[i]);        else c.push_back(a[i]);    }    if(b.size()==0){        cout <<"-1" << "\n";        return;    }    cout << b.size()<<" "<<c.size() << "\n";    for (auto x : b) cout << x<< " ";    cout << "\n";    for (auto x : c) cout << x<< " ";    cout << "\n";             } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}